{
  "skill_name": "sylvia-iot-services",
  "evals": [
    {
      "id": 0,
      "prompt": "我要開始跑 sylvia-iot-gui-genai 的 E2E 測試，需要把 backend 啟動起來",
      "expected_output": "詢問或推斷要用 core 還是 router，然後提供正確的 scripts 下載和 start.sh 指令（不含 GUI，SQLite）",
      "files": [],
      "assertions": [
        {
          "id": "downloads_to_tmp",
          "description": "有提到從 GitHub 下載 scripts 到 /tmp",
          "type": "grep",
          "pattern": "/tmp"
        },
        {
          "id": "uses_scripts_method",
          "description": "使用 scripts 方式（start.sh）而非 compose/kustomize",
          "type": "grep",
          "pattern": "start\\.sh"
        },
        {
          "id": "no_gui_flag",
          "description": "不包含 --gui 選項（E2E 測試不需要）",
          "type": "grep_absent",
          "pattern": "--gui"
        },
        {
          "id": "prerequisite_check",
          "description": "有提到檢查 Docker 和/或 sqlite3",
          "type": "grep",
          "pattern": "docker|sqlite3"
        }
      ]
    },
    {
      "id": 1,
      "prompt": "我下午要給客戶展示 sylvia-iot 平台，需要有路由器功能和完整的 GUI，幫我把展示環境架起來",
      "expected_output": "使用 scripts 方式，--bin router --with lora-ifroglab,app-demo --gui，提供完整的下載和執行步驟",
      "files": [],
      "assertions": [
        {
          "id": "downloads_to_tmp",
          "description": "有提到從 GitHub 下載 scripts 到 /tmp",
          "type": "grep",
          "pattern": "/tmp"
        },
        {
          "id": "uses_router_bin",
          "description": "使用 --bin router",
          "type": "grep",
          "pattern": "router"
        },
        {
          "id": "includes_optional_services",
          "description": "包含 lora-ifroglab 和 app-demo",
          "type": "grep",
          "pattern": "lora-ifroglab"
        },
        {
          "id": "includes_gui",
          "description": "包含 --gui 選項",
          "type": "grep",
          "pattern": "--gui"
        }
      ]
    },
    {
      "id": 2,
      "prompt": "我要在家裡的 NAS 上架設 sylvia-iot，用 docker compose，hostname 設成 nas.local",
      "expected_output": "使用 compose 方式，下載 scripts 到 /tmp，執行 setup.sh --host nas.local",
      "files": [],
      "assertions": [
        {
          "id": "downloads_to_tmp",
          "description": "有提到從 GitHub 下載 scripts 到 /tmp",
          "type": "grep",
          "pattern": "/tmp"
        },
        {
          "id": "uses_compose_method",
          "description": "使用 compose 方式（setup.sh）",
          "type": "grep",
          "pattern": "setup\\.sh"
        },
        {
          "id": "sets_hostname",
          "description": "包含 --host nas.local",
          "type": "grep",
          "pattern": "nas\\.local"
        },
        {
          "id": "mentions_stop_command",
          "description": "提到如何停止服務（--down）",
          "type": "grep",
          "pattern": "\\-\\-down"
        }
      ]
    }
  ]
}
